import { API } from '../core/api.js';
import { AppState } from './dashboard.js';
import { Notifications } from '../ui/notifications.js';
import { Modal } from '../ui/modal.js';

const Appointments = (() => {
  let appointments = [];

  async function load() {
    const content = document.getElementById('dashboardContent');
    if (!content) return;

    content.innerHTML = `
          <div class="appointments-container fade-in">
            <div class="section-card p-6 glass-card">
              <div class="section-header flex justify-between items-center mb-6">
                <h3 class="section-title">Appointments</h3>
                <button class="btn btn-sm btn-primary" onclick="Appointments.openScheduleModal()">
                  Schedule New
                </button>
              </div>

              <div class="appointment-section mb-8">
                <h4 class="subsection-title mb-4 opacity-50 text-sm">Today's Appointments</h4>
                <div id="todayAppointments" class="appointment-list flex flex-col gap-3">
                   <div class="p-4 opacity-50">Loading appointments...</div>
                </div>
              </div>

              <div class="appointment-section">
                <h4 class="subsection-title mb-4 opacity-50 text-sm">Upcoming</h4>
                <div id="upcomingAppointments" class="appointment-list flex flex-col gap-3">
                   <div class="p-4 opacity-50">Loading appointments...</div>
                </div>
              </div>
            </div>
          </div>
        `;

    await fetchAppointments();
  }

  async function fetchAppointments() {
    if (AppState.isDemoMode) {
      appointments = generateDemoAppointments();
    } else {
      const result = await API.getAppointments(AppState.user.id);
      if (result.success) appointments = result.data || [];
    }
    renderAppointments();
  }

  function generateDemoAppointments() {
    const names = ['Sarah Johnson', 'Michael Chen', 'Lisa Patel', 'James Wilson', 'Emma Garcia'];
    const now = new Date();
    return names.map((name, i) => ({
      id: `demo-apt-${i}`,
      patient_name: name,
      scheduled_at: new Date(now.getTime() + (i - 1) * 3600000).toISOString(),
      duration_minutes: 30,
      status: i === 1 ? 'completed' : 'scheduled'
    }));
  }

  function renderAppointments() {
    const todayStr = new Date().toDateString();

    const todayList = appointments.filter(a =>
      new Date(a.scheduled_at).toDateString() === todayStr
    );
    const upcoming = appointments.filter(a =>
      new Date(a.scheduled_at).toDateString() !== todayStr &&
      new Date(a.scheduled_at) > new Date()
    );

    const todayEl = document.getElementById('todayAppointments');
    const upcomingEl = document.getElementById('upcomingAppointments');

    if (todayEl) {
      todayEl.innerHTML = todayList.length === 0
        ? '<div class="p-4 text-center opacity-30">No appointments today.</div>'
        : todayList.map(renderAppointmentCard).join('');
    }

    if (upcomingEl) {
      upcomingEl.innerHTML = upcoming.length === 0
        ? '<div class="p-4 text-center opacity-30">No upcoming appointments.</div>'
        : upcoming.map(renderAppointmentCard).join('');
    }
  }

  function renderAppointmentCard(apt) {
    const time = new Date(apt.scheduled_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const isCompleted = apt.status === 'completed';
    const isCancelled = apt.status === 'cancelled';

    let statusClass = 'bg-white/5';
    if (apt.status === 'scheduled') statusClass = 'bg-blue-500/20 text-blue-400';
    if (apt.status === 'completed') statusClass = 'bg-green-500/20 text-green-400';
    if (apt.status === 'cancelled') statusClass = 'bg-red-500/20 text-red-400';

    return `
          <div class="appointment-card glass-card p-4 rounded-xl border border-white/5 flex items-center justify-between ${isCompleted || isCancelled ? 'opacity-40' : ''}">
            <div class="apt-time flex flex-col min-w-[80px]">
              <span class="font-black text-xl">${time}</span>
              <span class="text-[10px] font-bold opacity-50 uppercase tracking-widest">${apt.duration_minutes} MIN</span>
            </div>
            <div class="apt-info flex-1 px-6 border-l border-white/5 ml-4">
              <span class="block font-bold text-base">${apt.patient_name || 'Generic Patient'}</span>
              <div class="flex items-center gap-2 mt-1">
                 <span class="text-[9px] font-black uppercase px-2 py-0.5 rounded ${statusClass}">${apt.status}</span>
                 <span class="text-[10px] opacity-40 italic">${new Date(apt.scheduled_at).toLocaleDateString()}</span>
              </div>
            </div>
            <div class="apt-actions flex gap-2">
              ${apt.status === 'scheduled' ? `
                <button class="btn btn-xs btn-action" onclick="Appointments.openRescheduleModal('${apt.id}')">Reschedule</button>
                <button class="btn btn-xs btn-outline-danger" onclick="Appointments.cancel('${apt.id}')">Cancel</button>
                <button class="btn btn-xs btn-primary" onclick="Appointments.markComplete('${apt.id}')">Complete</button>
              ` : ''}
            </div>
          </div>
        `;
  }

  function openScheduleModal() {
    const patients = window.Patients?.getAll() || [];
    const modalBody = document.querySelector('#appointmentModal .modal-body');
    if (!modalBody) return;

    modalBody.innerHTML = `
      <form id="scheduleForm" class="p-4">
        <div class="form-group mb-4">
          <label class="block text-xs font-bold opacity-50 mb-1">SELECT PATIENT</label>
          <select id="aptPatient" class="form-input" required>
            <option value="">Choose Patient...</option>
            ${patients.map(p => `<option value="${p.id}">${p.name}</option>`).join('')}
          </select>
        </div>
        <div class="grid grid-cols-2 gap-4 mb-4">
          <div class="form-group">
            <label class="block text-xs font-bold opacity-50 mb-1">DATE</label>
            <input type="date" id="aptDate" class="form-input" required>
          </div>
          <div class="form-group">
            <label class="block text-xs font-bold opacity-50 mb-1">TIME</label>
            <input type="time" id="aptTime" class="form-input" required>
          </div>
        </div>
        <div class="form-group mb-6">
          <label class="block text-xs font-bold opacity-50 mb-1">DURATION (MINUTES)</label>
          <select id="aptDuration" class="form-input">
            <option value="15">15 Minutes</option>
            <option value="30" selected>30 Minutes</option>
            <option value="45">45 Minutes</option>
            <option value="60">1 Hour</option>
          </select>
        </div>
        <button type="submit" class="btn btn-primary w-full">Confirm Appointment</button>
      </form>
    `;

    Modal.open('appointmentModal');

    document.getElementById('scheduleForm')?.addEventListener('submit', async (e) => {
      e.preventDefault();
      const btn = e.target.querySelector('button[type="submit"]');
      if (btn) btn.disabled = true;

      const date = document.getElementById('aptDate').value;
      const time = document.getElementById('aptTime').value;
      const patientId = document.getElementById('aptPatient').value;
      const patientName = patients.find(p => p.id === patientId)?.name;

      const aptData = {
        doctor_id: AppState.user.id,
        patient_id: patientId,
        patient_name: patientName,
        scheduled_at: `${date}T${time}:00`,
        duration_minutes: parseInt(document.getElementById('aptDuration').value),
        status: 'scheduled',
        created_at: new Date().toISOString()
      };

      const { success } = await API.addAppointment(aptData);
      if (success) {
        Notifications.success('Appointment synchronized with clinical calendar.');
        Modal.close('appointmentModal');
        await fetchAppointments();

        await API.logAction({
          action_type: 'SCHEDULE_APPOINTMENT',
          user_id: AppState.user.id,
          entity: 'appointments',
          new_data: aptData
        });
      }
      if (btn) btn.disabled = false;
    });
  }

  async function markComplete(id) {
    const { success } = await API.updateAppointment(id, { status: 'completed' });
    if (success) {
      Notifications.success('Appointment marked as completed.');
      await fetchAppointments();
    }
  }

  function openRescheduleModal(id) {
    const apt = appointments.find(a => a.id === id);
    if (!apt) return;

    // Reuse modal for rescheduling
    openScheduleModal();

    const form = document.getElementById('scheduleForm');
    const submitBtn = form.querySelector('button[type="submit"]');
    if (submitBtn) submitBtn.textContent = 'Confirm Rescheduling';

    // Prefill
    document.getElementById('aptPatient').value = apt.patient_id || '';
    document.getElementById('aptPatient').disabled = true;

    form.onsubmit = async (e) => {
      e.preventDefault();
      const date = document.getElementById('aptDate').value;
      const time = document.getElementById('aptTime').value;

      const updates = {
        scheduled_at: `${date}T${time}:00`,
        status: 'rescheduled',
        updated_at: new Date().toISOString()
      };

      const { success } = await API.updateAppointment(id, updates);
      if (success) {
        Notifications.success('Clinical session rescheduled.');
        Modal.close('appointmentModal');
        await fetchAppointments();
      }
    };
  }

  return { load, openScheduleModal, cancel, markComplete, openRescheduleModal };
})();

export { Appointments };
window.Appointments = Appointments;


